  static void show({
    required BuildContext context,
    required List<GlobalKey> targetKeys,
    GlobalKey? graphExampleKey,
    VoidCallback? onFinish,
    VoidCallback? onLaunchUrl,
  }) {
    // Set orientation to portrait when coach marks are shown
    SystemChrome.setPreferredOrientations([
      DeviceOrientation.portraitUp,
      DeviceOrientation.portraitDown,
    ]);

    final targets = createTargets(
      context: context,
      recordButtonKey: targetKeys[0],
      analysisModeKey: targetKeys[1],
      focusButtonKey: targetKeys[2],
      configurationKey: targetKeys[3],
      onLaunchUrl: onLaunchUrl,
    );

    TutorialCoachMark(
      colorShadow: backgroundColor.withValues(alpha: 0.7),
      targets: targets,
      alignSkip: Alignment.topRight,
      hideSkip: true,
      onFinish: () {
        // Reset orientation to allow all orientations when finished
        SystemChrome.setPreferredOrientations([
          DeviceOrientation.portraitUp,
          DeviceOrientation.portraitDown,
          DeviceOrientation.landscapeLeft,
          DeviceOrientation.landscapeRight,
        ]);
        onFinish?.call();
      },
    ).show(context: context);
  }
}

