// Flutter imports:
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:tutorial_coach_mark/tutorial_coach_mark.dart';

// Project imports:
import 'package:baseball_detector_flutter/gen/assets.gen.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';

class RecordingCoachMarks {
  static const double borderRadius = 8.0;
  static const Color primaryColor = Color(0xFF0052CC);
  static const Color backgroundColor = Color(0xFF091E42);

  static List<TargetFocus> createTargets({
    required BuildContext context,
    required GlobalKey recordButtonKey,
    required GlobalKey analysisModeKey,
    required GlobalKey focusButtonKey,
    required GlobalKey configurationKey,
    void Function(int currentStep, int totalSteps)? onStepChange,
    VoidCallback? onLaunchUrl,
  }) {
    final l10n = context.l10n;
    return [
      TargetFocus(
        paddingFocus: 0,
        identify: "try_recording",
        keyTarget: recordButtonKey,
        shape: ShapeLightFocus.Circle,
        radius: borderRadius,
        contents: [
          TargetContent(
            align: ContentAlign.top,
            builder: (context, controller) {
              return _buildImageWithChecklistCard(
                context: context,
                title: l10n.recording_coach_marks__try_recording_title,
                description:
                    l10n.recording_coach_marks__try_recording_description,
                image: Assets.images.imgPitcherSidePositionEn.path,
                checklistItems: [
                  l10n.recording_coach_marks__try_recording_checklist_1,
                  l10n.recording_coach_marks__try_recording_checklist_2,
                  l10n.recording_coach_marks__try_recording_checklist_3,
                ],
                currentStep: 4,
                totalSteps: 4,
                onNext: () {
                  onStepChange?.call(4, 4);
                  controller.next();
                },
                onLaunchUrl: onLaunchUrl,
              );
            },
          ),
        ],
      ),

      // Analysis mode selection
      TargetFocus(
        identify: "analysis_mode",
        keyTarget: analysisModeKey,
        shape: ShapeLightFocus.Circle,
        radius: borderRadius,
        contents: [
          TargetContent(
            align: ContentAlign.top,
            builder: (context, controller) {
              return _buildCoachMarkCard(
                context: context,
                title: l10n.recording_coach_marks__analysis_mode_title,
                description:
                    l10n.recording_coach_marks__analysis_mode_description,
                icon: Icons.settings_outlined,
                tips: [
                  l10n.recording_coach_marks__analysis_mode_tip_pitching,
                  l10n.recording_coach_marks__analysis_mode_tip_hitting,
                ],
                onNext: () {
                  onStepChange?.call(2, 3);
                  controller.next();
                },
                onLaunchUrl: onLaunchUrl,
              );
            },
          ),
        ],
      ),

      // Focus settings
      TargetFocus(
        identify: "focus",
        keyTarget: focusButtonKey,
        shape: ShapeLightFocus.Circle,
        radius: borderRadius,
        contents: [
          TargetContent(
            align: ContentAlign.top,
            builder: (context, controller) {
              return _buildCoachMarkCard(
                context: context,
                title: l10n.recording_coach_marks__focus_title,
                description: l10n.recording_coach_marks__focus_description,
                icon: Icons.center_focus_strong_outlined,
                tips: [
                  l10n.recording_coach_marks__focus_tip_af_to_mf,
                  l10n.recording_coach_marks__focus_tip_behind_pitcher,
                  l10n.recording_coach_marks__focus_tip_behind_catcher,
                ],
                onNext: () {
                  onStepChange?.call(3, 4);
                  controller.next();
                },
                onLaunchUrl: onLaunchUrl,
              );
            },
          ),
        ],
      ),
    ];
  }

  /// 統合されたコーチマークカードビルダー
  ///
  /// アイコン付きヘッダー、画像、チップス、チェックリストなど、
  /// 様々なコンテンツタイプを柔軟に表示できる統一されたカード UI を提供します。
  static Widget _buildCoachMarkCard({
    required BuildContext context,
    required VoidCallback? onNext,
    required VoidCallback? onLaunchUrl,
    String? title,
    String? description,
    IconData? icon,
    String? image,
    List<String>? tips,
    List<String>? checklistItems,
  }) {
    return Stack(
      alignment: Alignment.bottomCenter,
      children: [
        Container(
          constraints: const BoxConstraints(maxWidth: 400),
          margin: const EdgeInsets.fromLTRB(24, 0, 24, 80),
          decoration: BoxDecoration(
            color: Colors.white,
            borderRadius: BorderRadius.circular(16),
            boxShadow: [
              BoxShadow(
                color: Colors.black.withValues(alpha: 0.08),
                blurRadius: 8,
                offset: const Offset(0, 2),
              ),
              BoxShadow(
                color: Colors.black.withValues(alpha: 0.04),
                blurRadius: 24,
                offset: const Offset(0, 8),
              ),
            ],
          ),
          child: ClipRRect(
            borderRadius: BorderRadius.circular(16),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                // Header with gradient (icon タイプの場合のみ)
                if (icon != null && title != null)
                  Container(
                    decoration: BoxDecoration(
                      gradient: LinearGradient(
                        colors: [
                          primaryColor.withValues(alpha: 0.08),
                          primaryColor.withValues(alpha: 0.04),
                        ],
                        begin: Alignment.topLeft,
                        end: Alignment.bottomRight,
                      ),
                    ),
                    child: Padding(
                      padding: const EdgeInsets.all(24),
                      child: Row(
                        children: [
                          Container(
                            width: 48,
                            height: 48,
                            decoration: BoxDecoration(
                              gradient: LinearGradient(
                                colors: [
                                  primaryColor,
                                  primaryColor.withValues(alpha: 0.8),
                                ],
                                begin: Alignment.topLeft,
                                end: Alignment.bottomRight,
                              ),
                              borderRadius: BorderRadius.circular(12),
                              boxShadow: [
                                BoxShadow(
                                  color: primaryColor.withValues(alpha: 0.3),
                                  blurRadius: 8,
                                  offset: const Offset(0, 4),
                                ),
                              ],
                            ),
                            child: Icon(
                              icon,
                              color: Colors.white,
                              size: 26,
                            ),
                          ),
                          const Gap(16),
                          Expanded(
                            child: Text(
                              title,
                              style: const TextStyle(
                                fontSize: 20,
                                fontWeight: FontWeight.w600,
                                color: Color(0xFF172B4D),
                                letterSpacing: -0.3,
                              ),
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),

                // Content
                Padding(
                  padding: const EdgeInsets.fromLTRB(24, 24, 24, 20),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      // Image display (画像タイプの場合)
                      if (image != null) ...[
                        ClipRRect(
                          borderRadius: BorderRadius.circular(12),
                          child: Image.asset(
                            image,
                            width: double.infinity,
                            fit: BoxFit.contain,
                          ),
                        ),
                        const Gap(20),
                      ],

                      // Description (アイコンタイプの場合)
                      if (description != null && icon != null)
                        Text(
                          description,
                          style: const TextStyle(
                            fontSize: 16,
                            color: Color(0xFF5E6C84),
                            height: 1.6,
                            letterSpacing: -0.2,
                          ),
                        ),

                      // Tips (番号付きリスト)
                      if (tips != null && tips.isNotEmpty) ...[
                        const Gap(20),
                        Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          mainAxisSize: MainAxisSize.min,
                          children: tips
                              .asMap()
                              .entries
                              .map((entry) => Padding(
                                    padding: EdgeInsets.only(
                                      bottom: entry.key < tips.length - 1
                                          ? 12
                                          : 0,
                                    ),
                                    child: Row(
                                      crossAxisAlignment:
                                          CrossAxisAlignment.start,
                                      children: [
                                        Container(
                                          width: 20,
                                          height: 20,
                                          margin:
                                              const EdgeInsets.only(top: 2),
                                          decoration: const BoxDecoration(
                                            color: Color(0xFFFF8B00),
                                            shape: BoxShape.circle,
                                          ),
                                          child: Center(
                                            child: Text(
                                              '${entry.key + 1}',
                                              style: const TextStyle(
                                                color: Colors.white,
                                                fontSize: 12,
                                                fontWeight: FontWeight.w600,
                                              ),
                                            ),
                                          ),
                                        ),
                                        const Gap(12),
                                        Expanded(
                                          child: Text(
                                            entry.value,
                                            style: const TextStyle(
                                              color: Color(0xFF172B4D),
                                              fontSize: 15,
                                              height: 1.5,
                                              fontWeight: FontWeight.w500,
                                              letterSpacing: -0.1,
                                            ),
                                          ),
                                        ),
                                      ],
                                    ),
                                  ))
                              .toList(),
                        ),
                      ],

                      // Checklist (チェックマーク付きリスト)
                      if (checklistItems != null &&
                          checklistItems.isNotEmpty)
                        Container(
                          width: double.infinity,
                          decoration: BoxDecoration(
                            color: const Color(0xFFF4F5F7),
                            borderRadius: BorderRadius.circular(12),
                            border: Border.all(
                              color: primaryColor.withValues(alpha: 0.2),
                              width: 1.5,
                            ),
                          ),
                          padding: const EdgeInsets.all(16),
                          child: Column(
                            children: checklistItems
                                .asMap()
                                .entries
                                .map((entry) => Padding(
                                      padding: EdgeInsets.only(
                                        bottom:
                                            entry.key < checklistItems.length - 1
                                                ? 12
                                                : 0,
                                      ),
                                      child: Row(
                                        children: [
                                          Icon(
                                            Icons.check_circle,
                                            size: 16,
                                            color: primaryColor,
                                          ),
                                          const Gap(8),
                                          Expanded(
                                            child: Text(
                                              entry.value,
                                              style: const TextStyle(
                                                color: Color(0xFF172B4D),
                                                fontSize: 15,
                                                height: 1.5,
                                                fontWeight: FontWeight.w500,
                                                letterSpacing: -0.1,
                                              ),
                                            ),
                                          ),
                                        ],
                                      ),
                                    ))
                                .toList(),
                          ),
                        ),
                    ],
                  ),
                ),
              ],
            ),
          ),
        ),
        GestureDetector(
          onTap: onNext,
          child: Container(
            width: context.screenWidth,
            height: context.screenHeight,
            color: Colors.transparent,
          ),
        ),
        if (onLaunchUrl != null)
          Align(
            alignment: Alignment.topRight,
            child: GestureDetector(
              onTap: () {
                onLaunchUrl.call();
              },
              child: Padding(
                padding: const EdgeInsets.all(16),
                child: Row(
                  crossAxisAlignment: CrossAxisAlignment.end,
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Assets.images.icYoutube.svg(width: 32),
                    const Gap(4),
                    Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        Text(
                          context.l10n.recording_coach_marks__more,
                          style: const TextStyle(
                            color: Colors.white,
                            fontSize: 14,
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                        const Gap(5),
                      ],
                    ),
                  ],
                ),
              ),
            ),
          )
      ],
    );
  }

  static void show({
    required BuildContext context,
    required List<GlobalKey> targetKeys,
    GlobalKey? graphExampleKey,
    VoidCallback? onFinish,
    VoidCallback? onLaunchUrl,
  }) {
    // Set orientation to portrait when coach marks are shown
    SystemChrome.setPreferredOrientations([
      DeviceOrientation.portraitUp,
      DeviceOrientation.portraitDown,
    ]);

    final targets = createTargets(
      context: context,
      recordButtonKey: targetKeys[0],
      analysisModeKey: targetKeys[1],
      focusButtonKey: targetKeys[2],
      configurationKey: targetKeys[3],
      onLaunchUrl: onLaunchUrl,
    );

    TutorialCoachMark(
      colorShadow: backgroundColor.withValues(alpha: 0.7),
      targets: targets,
      alignSkip: Alignment.topRight,
      hideSkip: true,
      onFinish: () {
        // Reset orientation to allow all orientations when finished
        SystemChrome.setPreferredOrientations([
          DeviceOrientation.portraitUp,
          DeviceOrientation.portraitDown,
          DeviceOrientation.landscapeLeft,
          DeviceOrientation.landscapeRight,
        ]);
        onFinish?.call();
      },
    ).show(context: context);
  }
}

